import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { getProduct, getProductReviews } from './woocommerce';
import { useCartStore } from './cartStore';

const ProductDetail = () => {
  const { id } = useParams();
  const [product, setProduct] = useState(null);
  const [reviews, setReviews] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [quantity, setQuantity] = useState(1);
  const { addToCart, openCart, getCartCount } = useCartStore();

  useEffect(() => {
    fetchProduct();
    fetchReviews();
  }, [id]);

  const fetchProduct = async () => {
    try {
      setLoading(true);
      const data = await getProduct(id);
      setProduct(data);
    } catch (err) {
      setError('Failed to load product');
      console.error('Error fetching product:', err);
    } finally {
      setLoading(false);
    }
  };

  const fetchReviews = async () => {
    try {
      const data = await getProductReviews(id);
      setReviews(data);
    } catch (err) {
      console.error('Error fetching reviews:', err);
    }
  };

  const handleAddToCart = () => {
    for (let i = 0; i < quantity; i++) {
      addToCart(product);
    }
    openCart();
  };

  if (loading) {
    return (
      <div className="product-detail">
        <header className="header">
          <div className="header-content">
            <h1>Ritchie Street Electronics</h1>
            <nav className="nav">
              <Link to="/">Home</Link>
              <Link to="/cart">Cart ({getCartCount()})</Link>
              <Link to="/login">Login</Link>
            </nav>
          </div>
        </header>
        <div className="loading">Loading product...</div>
      </div>
    );
  }

  if (error || !product) {
    return (
      <div className="product-detail">
        <header className="header">
          <div className="header-content">
            <h1>Ritchie Street Electronics</h1>
            <nav className="nav">
              <Link to="/">Home</Link>
              <Link to="/cart">Cart ({getCartCount()})</Link>
              <Link to="/login">Login</Link>
            </nav>
          </div>
        </header>
        <div className="error-message">{error || 'Product not found'}</div>
      </div>
    );
  }

  return (
    <div className="product-detail">
      <header className="header">
        <div className="header-content">
          <h1>Ritchie Street Electronics</h1>
          <nav className="nav">
            <Link to="/">Home</Link>
            <Link to="/cart">Cart ({getCartCount()})</Link>
            <Link to="/login">Login</Link>
          </nav>
        </div>
      </header>

      <div className="product-detail-container">
        <div className="product-gallery">
          {product.images && product.images.length > 0 ? (
            <img src={product.images[0].src} alt={product.name} className="main-image" />
          ) : (
            <div className="no-image">No image available</div>
          )}
        </div>

        <div className="product-info">
          <h1 className="product-title">{product.name}</h1>
          <p className="product-price">₹{parseFloat(product.price).toFixed(2)}</p>
          {product.stock_status === 'instock' ? (
            <p className="stock-status in-stock">In Stock</p>
          ) : (
            <p className="stock-status out-of-stock">Out of Stock</p>
          )}

          <div 
            className="product-description"
            dangerouslySetInnerHTML={{ __html: product.description }}
          />

          <div className="quantity-selector">
            <label>Quantity:</label>
            <button 
              onClick={() => setQuantity(Math.max(1, quantity - 1))}
              disabled={quantity <= 1}
            >
              -
            </button>
            <span>{quantity}</span>
            <button onClick={() => setQuantity(quantity + 1)}>+</button>
          </div>

          <button 
            className="add-to-cart-btn"
            onClick={handleAddToCart}
            disabled={product.stock_status !== 'instock'}
          >
            Add to Cart
          </button>

          <Link to="/cart" className="view-cart-btn">View Cart</Link>
        </div>
      </div>

      {reviews.length > 0 && (
        <div className="product-reviews">
          <h2>Customer Reviews</h2>
          <div className="reviews-list">
            {reviews.map(review => (
              <div key={review.id} className="review-item">
                <div className="review-header">
                  <span className="reviewer-name">{review.reviewer}</span>
                  <span className="review-date">
                    {new Date(review.date_created).toLocaleDateString()}
                  </span>
                </div>
                <div className="review-rating">
                  {'★'.repeat(review.rating)}{'☆'.repeat(5 - review.rating)}
                </div>
                <p className="review-content" dangerouslySetInnerHTML={{ __html: review.review }} />
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default ProductDetail;
